import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/export_options.dart';

void main() {
  group('ExportFormat', () {
    test('extension returns correct file extensions', () {
      expect(ExportFormat.png.extension, 'png');
      expect(ExportFormat.jpg.extension, 'jpg');
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('mimeType returns correct MIME types', () {
      expect(ExportFormat.png.mimeType, 'image/png');
      expect(ExportFormat.jpg.mimeType, 'image/jpeg');
      expect(ExportFormat.webp.mimeType, 'image/webp');
    });
  });

  group('ExportResolution', () {
    test('dimensions returns correct values for preset resolutions', () {
      expect(ExportResolution.hd.dimensions, (1280, 720));
      expect(ExportResolution.fullHd.dimensions, (1920, 1080));
      expect(ExportResolution.quadHd.dimensions, (2560, 1440));
      expect(ExportResolution.uhd4k.dimensions, (3840, 2160));
      expect(ExportResolution.instagram.dimensions, (1080, 1080));
      expect(ExportResolution.instagramStory.dimensions, (1080, 1920));
      expect(ExportResolution.twitter.dimensions, (1200, 675));
    });

    test('screen and custom resolutions return null dimensions', () {
      expect(ExportResolution.screen.dimensions, isNull);
      expect(ExportResolution.custom.dimensions, isNull);
    });

    test('isSocialPreset identifies social presets correctly', () {
      expect(ExportResolution.instagram.isSocialPreset, isTrue);
      expect(ExportResolution.instagramStory.isSocialPreset, isTrue);
      expect(ExportResolution.twitter.isSocialPreset, isTrue);
      expect(ExportResolution.fullHd.isSocialPreset, isFalse);
      expect(ExportResolution.uhd4k.isSocialPreset, isFalse);
    });
  });

  group('ExportOptions', () {
    test('default options have sensible values', () {
      const options = ExportOptions();
      expect(options.format, ExportFormat.png);
      expect(options.resolution, ExportResolution.fullHd);
      expect(options.quality, 95);
      expect(options.embedMetadata, isTrue);
      expect(options.transparentBackground, isFalse);
    });

    test('calculatePixelRatio returns correct ratio for preset resolutions',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      // Portrait screen 400x800 -> Full HD adapts to 1080x1920.
      // Ratios: 1080/400 = 2.7, 1920/800 = 2.4 -> max = 2.7
      final ratio = options.calculatePixelRatio(400, 800);
      expect(ratio, closeTo(2.7, 0.1));
    });

    test('calculatePixelRatio is clamped to 8.0 max', () {
      const options = ExportOptions(resolution: ExportResolution.uhd4k);
      // Screen 100x100 -> would need 38.4 ratio, but clamped to 8
      final ratio = options.calculatePixelRatio(100, 100);
      expect(ratio, 8.0);
    });

    test('calculatePixelRatio sanitizes invalid screen dimensions for presets',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);

      expect(options.calculatePixelRatio(-400, -800), 8.0);
    });

    test('getTargetDimensions returns correct dimensions', () {
      const options = ExportOptions(resolution: ExportResolution.instagram);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1080));
    });

    test('getTargetDimensions adapts preset orientation to screen orientation',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1920));
    });

    test('social preset dimensions preserve platform crop contracts', () {
      const instagramStory = ExportOptions(
        resolution: ExportResolution.instagramStory,
      );
      const twitter = ExportOptions(resolution: ExportResolution.twitter);

      expect(instagramStory.getTargetDimensions(1200, 800), (1080, 1920));
      expect(twitter.getTargetDimensions(400, 800), (1200, 675));
      expect(
        instagramStory.calculatePixelRatio(1200, 800),
        closeTo(2.4, 0.01),
      );
    });

    test('custom resolution uses customWidth and customHeight', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (2000, 1500));
    });

    test('custom resolution ignores non-positive dimensions', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 0,
        customHeight: -10,
      );

      expect(options.getTargetDimensions(400, 800), (400, 800));
      expect(options.calculatePixelRatio(400, 800), 1.0);
    });

    test('custom resolution can fall back one axis at a time', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 0,
      );

      expect(options.getTargetDimensions(400, 800), (2000, 800));
      expect(options.calculatePixelRatio(400, 800), 5.0);
    });

    test('custom resolution clamps huge dimensions to safe image bounds', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 1 << 40,
        customHeight: 1 << 35,
      );

      expect(options.getTargetDimensions(400, 800), (1 << 30, 1 << 30));
      expect(options.calculatePixelRatio(400, 800), 8.0);
    });

    test('screen dimensions used for fallback are at least one pixel', () {
      const options = ExportOptions(resolution: ExportResolution.custom);

      expect(options.getTargetDimensions(0, -20), (1, 1));
      expect(options.calculatePixelRatio(0, -20), 1.0);
    });

    test('copyWith creates new instance with updated values', () {
      const original = ExportOptions();
      final updated = original.copyWith(
        format: ExportFormat.jpg,
        quality: 80,
      );

      expect(updated.format, ExportFormat.jpg);
      expect(updated.quality, 80);
      expect(updated.resolution, original.resolution); // Unchanged
    });

    test('copyWith clears nullable custom dimensions when null is explicit',
        () {
      const original = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );

      final updated = original.copyWith(
        customWidth: null,
        customHeight: null,
      );

      expect(updated.customWidth, isNull);
      expect(updated.customHeight, isNull);
      expect(updated.getTargetDimensions(400, 800), (400, 800));
    });

    test('copyWith clears nullable provenance fields when null is explicit',
        () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(
        metadata: null,
        watermarkText: null,
      );

      expect(updated.metadata, isNull);
      expect(updated.watermarkText, isNull);
    });

    test('copyWith omits nullable provenance fields without clearing them', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(quality: 80);

      expect(updated.metadata, same(metadata));
      expect(updated.watermarkText, 'Flutter Fractals');
    });
  });

  group('ExportMetadata', () {
    test('toExifMap returns expected keys', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );

      final exif = metadata.toExifMap();
      expect(exif, containsPair('Software', contains('Flutter Fractals')));
      expect(exif, containsPair('Artist', 'Flutter Fractals'));
      expect(exif, containsPair('UserComment', contains('mandelbrot')));
    });

    test('snapshots parameters before export metadata is reused', () {
      final params = <String, Object>{'iterations': 100};
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: params,
        createdAt: DateTime(2024, 1, 15),
      );

      params['iterations'] = 200;
      params['bailout'] = 4.0;

      expect(metadata.parameters, equals({'iterations': 100}));
      expect(
        () => metadata.parameters['iterations'] = 300,
        throwsUnsupportedError,
      );
      expect(metadata.toExifMap()['UserComment'], contains('iterations: 100'));
      expect(metadata.toExifMap()['UserComment'], isNot(contains('200')));
      expect(metadata.toExifMap()['UserComment'], isNot(contains('bailout')));
    });

    test('snapshots nested collection parameter values before metadata reuse',
        () {
      final paletteStops = <double>[0.1, 0.2];
      final palette = <String, Object>{'stops': paletteStops};
      final metadata = ExportMetadata(
        fractalType: 'custom_fractal',
        parameters: {
          'palette': palette,
          'weights': paletteStops,
        },
        createdAt: DateTime(2024, 1, 15),
      );

      paletteStops.add(0.3);
      palette['mode'] = 'mutated';

      final comment = metadata.toExifMap()['UserComment']!;
      expect(comment, contains('palette: {stops: [0.1, 0.2]}'));
      expect(comment, contains('weights: [0.1, 0.2]'));
      expect(comment, isNot(contains('0.3')));
      expect(comment, isNot(contains('mutated')));

      final snapshotPalette =
          metadata.parameters['palette'] as Map<Object?, Object?>;
      final snapshotWeights = metadata.parameters['weights'] as List<Object?>;
      expect(() => snapshotPalette['mode'] = 'mutated', throwsUnsupportedError);
      expect(() => snapshotWeights.add(0.4), throwsUnsupportedError);
    });
  });

  group('ExportPresets', () {
    test('socialShare preset has correct settings', () {
      expect(ExportPresets.socialShare.format, ExportFormat.jpg);
      expect(ExportPresets.socialShare.resolution, ExportResolution.instagram);
      expect(ExportPresets.socialShare.quality, 90);
    });

    test('highQualityPng preset has correct settings', () {
      expect(ExportPresets.highQualityPng.format, ExportFormat.png);
      expect(ExportPresets.highQualityPng.resolution, ExportResolution.uhd4k);
    });

    test('webOptimized preset has correct settings', () {
      expect(ExportPresets.webOptimized.format, ExportFormat.webp);
      expect(ExportPresets.webOptimized.resolution, ExportResolution.fullHd);
      expect(ExportPresets.webOptimized.quality, 85);
    });

    test('transparentOverlay preset has correct settings', () {
      expect(ExportPresets.transparentOverlay.format, ExportFormat.png);
      expect(ExportPresets.transparentOverlay.transparentBackground, isTrue);
    });
  });
}

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Replayable CPU viewport center.
///
/// The controller normally provides finite pan coordinates, but CPU fallback
/// code also accepts replayed/isolate scalar requests. Non-finite pan samples
/// must not poison every formula coordinate with NaN/Infinity, so they adopt
/// the origin instead.
final class CpuViewportCenter {
  const CpuViewportCenter({required this.x, required this.y});

  final double x;
  final double y;

  factory CpuViewportCenter.fromScalars({
    required double panX,
    required double panY,
  }) {
    return CpuViewportCenter(
      x: normalizeCoordinate(panX),
      y: normalizeCoordinate(panY),
    );
  }

  static double normalizeCoordinate(double value) {
    return value.isFinite ? value : 0.0;
  }
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  }) : this._(
          center: CpuViewportCenter.fromScalars(panX: panX, panY: panY),
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping._({
    required CpuViewportCenter center,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = center.x,
        centerY = center.y,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'dart:async';

import 'package:flutter_fractals/features/renderer/cpu/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu/cpu_tile_worker.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CpuTileWorker', () {
    test('propagates tile render failures instead of hanging', () async {
      final worker = await CpuTileWorker.spawn();
      addTearDown(worker.dispose);

      final future = worker.renderTile(_tileRequest(x0: 3, w: 2)).timeout(
            const Duration(seconds: 1),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile did not reply to an invalid tile',
            ),
          );

      await expectLater(
        future,
        throwsA(
          isA<CpuTileWorkerException>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('rejects jobs submitted after disposal instead of waiting forever',
        () async {
      final worker = await CpuTileWorker.spawn();
      worker.dispose();

      final future = worker.renderTile(_tileRequest()).timeout(
            const Duration(milliseconds: 200),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile waited on a disposed worker',
            ),
          );

      await expectLater(future, _throwsDisposedWorkerStateError);
    });

    test('rejects pending jobs when disposal races an in-flight tile',
        () async {
      final worker = await CpuTileWorker.spawn();

      final future = worker.renderTile(_tileRequest()).timeout(
            const Duration(milliseconds: 200),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile waited after disposal closed a job',
            ),
          );
      final expectation = expectLater(future, _throwsDisposedWorkerStateError);
      worker.dispose();

      await expectation;
    });
  });
}

Matcher get _throwsDisposedWorkerStateError => throwsA(
      isA<StateError>().having(
        (error) => error.message,
        'message',
        contains('disposed'),
      ),
    );

CpuTileRenderRequest _tileRequest({
  int fullWidth = 4,
  int fullHeight = 4,
  int x0 = 0,
  int y0 = 0,
  int w = 1,
  int h = 1,
}) {
  return CpuTileRenderRequest(
    moduleId: 'mandelbrot',
    panX: 0.0,
    panY: 0.0,
    zoom: 1.0,
    iterations: 32,
    bailout: 4.0,
    juliaCX: -0.8,
    juliaCY: 0.156,
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
    sampleCount: 1,
  );
}

import 'package:flutter_fractals/features/renderer/cpu/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu/cpu_render_isolate.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU frame raster contracts', () {
    test('direct and isolate full-frame renders share the same bytes',
        () async {
      final direct = await renderCpuFrame(
        moduleId: 'julia',
        viewPan: Vector2(-0.25, 0.1),
        viewZoom: 2.0,
        iterations: 40,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 3,
        height: 2,
        sampleCount: 4,
      );

      const isolateRequest = CpuRenderRequest(
        moduleId: 'julia',
        panX: -0.25,
        panY: 0.1,
        zoom: 2.0,
        iterations: 40,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: 3,
        height: 2,
        sampleCount: 4,
      );
      final isolate = renderCpuFrameInIsolate(isolateRequest);

      expect(direct.width, isolate.width);
      expect(direct.height, isolate.height);
      expect(direct.rgba, isolate.rgba);
    });

    test('direct full-frame render rejects non-positive dimensions', () async {
      await expectLater(
        renderCpuFrame(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 32,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 0,
          height: 4,
        ),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.name,
            'name',
            'full viewport',
          ),
        ),
      );
    });
  });
}

