+        widget.onUserInteraction?.call();
       }
+      _animateZoomTo(
+        zoom,
+        (zoom * 0.5).clamp(_kMinZoom, _kMaxZoom),
+        focalPoint: midpoint,
+        onCompleted: () {
+          _deferUserInteractionEndToAnimation = false;
+          if (widget.onUserInteractionEnd != null) {
+            widget.onUserInteractionEnd!.call();
+          } else {
+            widget.onUserInteraction?.call();
+          }
+        },
+      );
+      HapticFeedback.lightImpact();
     }

     // Check single-finger double-tap (only when 1 finger remains)

import 'dart:ui' show Offset;

/// Replayable decision for the renderer's two-finger tap shortcut.
///
/// The gesture mixin receives raw pointer-up and pointer-cancel events through
/// the same cleanup path. Keeping the acceptance criteria pure makes event-order
/// assumptions visible in focused tests instead of hiding them behind timers,
/// haptics, and animation side effects.
final class RendererTwoFingerTapDecision {
  static const int maxDurationMs = 220;

  const RendererTwoFingerTapDecision._({required this.midpoint});

  final Offset? midpoint;

  bool get shouldTrigger => midpoint != null;

  static RendererTwoFingerTapDecision evaluate({
    required bool isPointerUp,
    required bool candidate,
    required int activePointerCount,
    required Duration? elapsed,
    required Iterable<Offset> activePositions,
  }) {
    if (!isPointerUp ||
        !candidate ||
        activePointerCount != 2 ||
        elapsed == null) {
      return const RendererTwoFingerTapDecision._(midpoint: null);
    }
    if (elapsed.inMilliseconds > maxDurationMs) {
      return const RendererTwoFingerTapDecision._(midpoint: null);
    }

    final points = activePositions.toList(growable: false);
    if (points.length != 2) {
      return const RendererTwoFingerTapDecision._(midpoint: null);
    }

    return RendererTwoFingerTapDecision._(
      midpoint: Offset(
        (points[0].dx + points[1].dx) / 2.0,
        (points[0].dy + points[1].dy) / 2.0,
      ),
    );
  }
}

import 'package:flutter_fractals/features/renderer/widgets/renderer/input/gesture_tap_classification.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('RendererTwoFingerTapDecision', () {
    test('accepts quick two-finger pointer-up and exposes midpoint', () {
      final decision = RendererTwoFingerTapDecision.evaluate(
        isPointerUp: true,
        candidate: true,
        activePointerCount: 2,
        elapsed: const Duration(milliseconds: 120),
        activePositions: const [Offset(10, 20), Offset(30, 60)],
      );

      expect(decision.shouldTrigger, isTrue);
      expect(decision.midpoint, const Offset(20, 40));
    });

    test(
        'rejects pointer cancel even while the tap candidate is otherwise valid',
        () {
      final decision = RendererTwoFingerTapDecision.evaluate(
        isPointerUp: false,
        candidate: true,
        activePointerCount: 2,
        elapsed: const Duration(milliseconds: 120),
        activePositions: const [Offset(10, 20), Offset(30, 60)],
      );

      expect(decision.shouldTrigger, isFalse);
      expect(decision.midpoint, isNull);
    });

    test('rejects stale, incomplete, or inconsistent candidates', () {
      final stale = RendererTwoFingerTapDecision.evaluate(
        isPointerUp: true,
        candidate: true,
        activePointerCount: 2,
        elapsed: const Duration(milliseconds: 221),
        activePositions: const [Offset(10, 20), Offset(30, 60)],
      );
      final missingStart = RendererTwoFingerTapDecision.evaluate(
        isPointerUp: true,
        candidate: true,
        activePointerCount: 2,
        elapsed: null,
        activePositions: const [Offset(10, 20), Offset(30, 60)],
      );
      final inconsistentPositions = RendererTwoFingerTapDecision.evaluate(
        isPointerUp: true,
        candidate: true,
        activePointerCount: 2,
        elapsed: const Duration(milliseconds: 120),
        activePositions: const [Offset(10, 20)],
      );

      expect(stale.shouldTrigger, isFalse);
      expect(missingStart.shouldTrigger, isFalse);
      expect(inconsistentPositions.shouldTrigger, isFalse);
    });
  });
}
